32: /**
33:  * This class encapsulates a classic group member's metadata.
34:  *
35:  * Member metadata contains the following:
36:  *
37:  * Heartbeat metadata:
38:  * 1. negotiated heartbeat session timeout
39:  * 2. timestamp of the latest heartbeat
40:  *
41:  * Protocol metadata:
42:  * 1. the list of supported protocols (ordered by preference)
43:  * 2. the metadata associated with each protocol
44:  *
45:  * In addition, it also contains the following state information:
46:  *
47:  * 1. Awaiting rebalance future: when the group is in the prepare-rebalance state,
48:  *                                 its rebalance future will be kept in the metadata if the
49:  *                                 member has sent the join group request
50:  * 2. Awaiting sync future: when the group is in the awaiting-sync state, its sync future
51:  *                            is kept in metadata until the leader provides the group assignment
52:  *                            and the group transitions to stable
53:  */
54: public class ClassicGroupMember {
55: 
56:     /**
57:      * An empty assignment.
58:      */
59:     public static final byte[] EMPTY_ASSIGNMENT = Bytes.EMPTY;
60: 
61:     /**
62:      * The member id.
63:      */
64:     private final String memberId;
65: 
66:     /**
67:      * The group instance id.
68:      */
69:     private final Optional<String> groupInstanceId;
70: 
71:     /**
72:      * The client id.
73:      */
74:     private final String clientId;
75: 
76:     /**
77:      * The client host.
78:      */
79:     private final String clientHost;
80: 
81:     /**
82:      * The rebalance timeout in milliseconds.
83:      */
84:     private int rebalanceTimeoutMs;
85: 
86:     /**
87:      * The session timeout in milliseconds.
88:      */
89:     private int sessionTimeoutMs;
90: 
91:     /**
92:      * The protocol type.
93:      */
94:     private final String protocolType;
95: 
96:     /**
97:      * The list of supported protocols.
98:      */
99:     private JoinGroupRequestProtocolCollection supportedProtocols;
100: 
101:     /**
102:      * The assignment stored by the client assignor.
103:      */
104:     private byte[] assignment;
105: 
106:     /**
107:      * The future that is invoked once this member joins the group.
108:      */
109:     private CompletableFuture<JoinGroupResponseData> awaitingJoinFuture = null;
110: 
111:     /**
112:      * The future that is invoked once this member completes the sync group phase.
113:      */
114:     private CompletableFuture<SyncGroupResponseData> awaitingSyncFuture = null;
115: 
116:     /**
117:      * Indicates whether the member is a new member of the group.
118:      */
119:     private boolean isNew = false;
120: 
121:     public ClassicGroupMember(
122:         String memberId,
123:         Optional<String> groupInstanceId,
124:         String clientId,
125:         String clientHost,
126:         int rebalanceTimeoutMs,
127:         int sessionTimeoutMs,
128:         String protocolType,
129:         JoinGroupRequestProtocolCollection supportedProtocols
130:     ) {
131:         this(
132:             memberId,
133:             groupInstanceId,
134:             clientId,
135:             clientHost,
136:             rebalanceTimeoutMs,
137:             sessionTimeoutMs,
138:             protocolType,
139:             supportedProtocols,
140:             EMPTY_ASSIGNMENT
141:         );
142:     }
143: 
144:     public ClassicGroupMember(
145:         String memberId,
146:         Optional<String> groupInstanceId,
147:         String clientId,
148:         String clientHost,
149:         int rebalanceTimeoutMs,
150:         int sessionTimeoutMs,
151:         String protocolType,
152:         JoinGroupRequestProtocolCollection supportedProtocols,
153:         byte[] assignment
154:     ) {
155:         this.memberId = memberId;
156:         this.groupInstanceId = groupInstanceId;
157:         this.clientId = clientId;
158:         this.clientHost = clientHost;
159:         this.rebalanceTimeoutMs = rebalanceTimeoutMs;
160:         this.sessionTimeoutMs = sessionTimeoutMs;
161:         this.protocolType = protocolType;
162:         this.supportedProtocols = supportedProtocols;
163:         this.assignment = assignment;
164:     }
165: 
166:     /**
167:      * @return true if the member is utilizing static membership, false otherwise.
168:      */
169:     public boolean isStaticMember() {
170:         return groupInstanceId.isPresent();
171:     }
172: 
173:     /**
174:      * @return whether the member is awaiting join.
175:      */
176:     public boolean isAwaitingJoin() {
177:         return awaitingJoinFuture != null;
178:     }
179: 
180:     /**
181:      * @return whether the member is awaiting sync.
182:      */
183:     public boolean isAwaitingSync() {
184:         return awaitingSyncFuture != null;
185:     }
186: 
187:     /**
188:      * Get the metadata corresponding to the provided protocol.
189:      */
190:     public byte[] metadata(String protocolName) {
191:         for (JoinGroupRequestProtocol protocol : supportedProtocols) {
192:             if (protocol.name().equals(protocolName)) {
193:                 return protocol.metadata();
194:             }
195:         }
196: 
197:         throw new IllegalArgumentException("Member does not support protocol " +
198:             protocolName);
199:     }
200: 
201:     /**
202:      * The heartbeat is always considered satisfied when an existing member has made a
203:      * successful join/sync group request during a rebalance.
204:      *
205:      * @return true if heartbeat was satisfied; false otherwise.
206:      */
207:     public boolean hasSatisfiedHeartbeat() {
208:         if (isNew) {
209:             // New members can be expired even while awaiting join, so we check this first
210:             return false;
211:         } else {
212:             // Members that are awaiting a rebalance automatically satisfy expected heartbeats
213:             return isAwaitingJoin() || isAwaitingSync();
214:         }
215:     }
216: 
217:     /**
218:      * Compare the given list of protocols with the member's supported protocols.
219:      *
220:      * @param protocols list of protocols to match.
221:      * @return true if the given list matches the member's list of supported protocols,
222:      *         false otherwise.
223:      */
224:     public boolean matches(JoinGroupRequestProtocolCollection protocols) {
225:         return protocols.equals(this.supportedProtocols);
226:     }
227: 
228:     /**
229:      * Vote for one of the potential group protocols. This takes into account the protocol preference as
230:      * indicated by the order of supported protocols and returns the first one also contained in the set
231:      *
232:      * @param candidates The protocol names that this member can vote for
233:      * @return the first supported protocol that matches one of the candidates
234:      */
235:     public String vote(Set<String> candidates) {
236:         for (JoinGroupRequestProtocol protocol : supportedProtocols) {
237:             if (candidates.contains(protocol.name())) {
238:                 return protocol.name();
239:             }
240:         }
241: 
242:         throw new IllegalArgumentException("Member does not support any of the candidate protocols");
243:     }
244: 
245:     /**
246:      * Transform protocols into their respective names.
247:      *
248:      * @param supportedProtocols list of supported protocols.
249:      * @return a set of protocol names from the given list of supported protocols.
250:      */
251:     public static Set<String> plainProtocolSet(
252:         JoinGroupRequestProtocolCollection supportedProtocols
253:     ) {
254:         Set<String> protocolNames = new HashSet<>();
255:         for (JoinGroupRequestProtocol protocol : supportedProtocols) {
256:             protocolNames.add(protocol.name());
257:         }
258:         return protocolNames;
259:     }
260: 
261:     /**
262:      * @return whether the member has an assignment set.
263:      */
264:     public boolean hasAssignment() {
265:         return assignment != null && assignment.length > 0;
266:     }
267: 
268:     /**
269:      * @return the member id.
270:      */
271:     public String memberId() {
272:         return memberId;
273:     }
274: 
275:     /**
276:      * @return the group instance id.
277:      */
278:     public Optional<String> groupInstanceId() {
279:         return groupInstanceId;
280:     }
281: 
282:     /**
283:      * @return the client id.
284:      */
285:     public String clientId() {
286:         return clientId;
287:     }
288: 
289:     /**
290:      * @return the client host.
291:      */
292:     public String clientHost() {
293:         return clientHost;
294:     }
295: 
296:     /**
297:      * @return the rebalance timeout in milliseconds.
298:      */
299:     public int rebalanceTimeoutMs() {
300:         return rebalanceTimeoutMs;
301:     }
302: 
303:     /**
304:      * @return the session timeout in milliseconds.
305:      */
306:     public int sessionTimeoutMs() {
307:         return sessionTimeoutMs;
308:     }
309: 
310:     /**
311:      * @return the protocol type.
312:      */
313:     public String protocolType() {
314:         return protocolType;
315:     }
316: 
317:     /**
318:      * @return the list of supported protocols.
319:      */
320:     public JoinGroupRequestProtocolCollection supportedProtocols() {
321:         return supportedProtocols;
322:     }
323: 
324:     /**
325:      * @return the member's assignment.
326:      */
327:     public byte[] assignment() {
328:         return assignment;
329:     }
330: 
331:     /**
332:      * @return the awaiting join future.
333:      */
334:     public CompletableFuture<JoinGroupResponseData> awaitingJoinFuture() {
335:         return awaitingJoinFuture;
336:     }
337: 
338:     /**
339:      * @return the awaiting sync future.
340:      */
341:     public CompletableFuture<SyncGroupResponseData> awaitingSyncFuture() {
342:         return awaitingSyncFuture;
343:     }
344: 
345:     /**
346:      * @return true if the member is new, false otherwise.
347:      */
348:     public boolean isNew() {
349:         return isNew;
350:     }
351: 
352:     /**
353:      * @return The described group member without metadata.
354:      */
355:     public DescribeGroupsResponseData.DescribedGroupMember describeNoMetadata() {
356:         return new DescribeGroupsResponseData.DescribedGroupMember()
357:             .setMemberId(memberId())
358:             .setGroupInstanceId(groupInstanceId().orElse(null))
359:             .setClientId(clientId())
360:             .setClientHost(clientHost())
361:             .setMemberAssignment(assignment());
362:     }
363: 
364:     /**
365:      * @return The described group member with metadata corresponding to the provided protocol.
366:      */
367:     public DescribeGroupsResponseData.DescribedGroupMember describe(String protocolName) {
368:         return describeNoMetadata().setMemberMetadata(metadata(protocolName));
369:     }
370: 
371:     /**
372:      * @param value the new rebalance timeout in milliseconds.
373:      */
374:     public void setRebalanceTimeoutMs(int value) {
375:         this.rebalanceTimeoutMs = value;
376:     }
377: 
378:     /**
379:      * @param value the new session timeout in milliseconds.
380:      */
381:     public void setSessionTimeoutMs(int value) {
382:         this.sessionTimeoutMs = value;
383:     }
384: 
385:     /**
386:      * @param value the new list of supported protocols.
387:      */
388:     public void setSupportedProtocols(JoinGroupRequestProtocolCollection value) {
389:         this.supportedProtocols = value;
390:     }
391: 
392:     /**
393:      * @param value the new assignment.
394:      */
395:     public void setAssignment(byte[] value) {
396:         this.assignment = value;
397:     }
398: 
399:     /**
400:      * @param value the updated join future.
401:      */
402:     public void setAwaitingJoinFuture(CompletableFuture<JoinGroupResponseData> value) {
403:         this.awaitingJoinFuture = value;
404:     }
405: 
406:     /**
407:      * @param value the updated sync future.
408:      */
409:     public void setAwaitingSyncFuture(CompletableFuture<SyncGroupResponseData> value) {
410:         this.awaitingSyncFuture = value;
411:     }
412: 
413:     /**
414:      * @param value true if the member is new, false otherwise.
415:      */
416:     public void setIsNew(boolean value) {
417:         this.isNew = value;
418:     }
419: 
420:     @Override
421:     public String toString() {
422:         return "ClassicGroupMember(" +
423:             "memberId='" + memberId + '\'' +
424:             ", groupInstanceId='" + groupInstanceId.orElse("") + '\'' +
425:             ", clientId='" + clientId + '\'' +
